                  autoComplete="off"
                  autoCorrect="off"
                  autoCapitalize="off"
                  spellCheck={false}
                  className="mt-1 w-full rounded border border-border bg-bg-raised px-3 py-2 text-sm text-fg outline-none transition-colors focus:border-accent"
