 22→fn debug_log(message: String) -> Result<(), String> {
 23→    use std::io::Write;
 24→    let timestamp = std::time::SystemTime::now()
 25→        .duration_since(std::time::UNIX_EPOCH)
 26→        .unwrap_or_default();
 27→    let line = format!(
 28→        "[{}.{:03}] [frontend] {}\n",
 29→        timestamp.as_secs(),
 30→        timestamp.subsec_millis(),
 31→        message
 32→    );
 33→    std::fs::OpenOptions::new()
 34→        .create(true)
 35→        .append(true)
 36→        .open("/tmp/entire-terminal-debug.log")
 37→        .and_then(|mut f| f.write_all(line.as_bytes()))
 38→        .map_err(|e| format!("Failed to write debug log: {}", e))
 39→}
