118→#[tauri::command]
119→fn get_transcript(
120→    repo_path: String,
121→    checkpoint_id: String,
122→    session_index: u32,
123→) -> Result<Vec<session::TranscriptMessage>, String> {
124→    let repo = git::open_repo(&repo_path)?;
125→
126→    let prefix = &checkpoint_id[..2];
127→    let suffix = &checkpoint_id[2..];
128→    let meta_path = format!("{}/{}/metadata.json", prefix, suffix);
129→    let meta_content = read_blob(&repo, &meta_path).ok();
130→    let candidates =
131→        transcript_candidate_paths(&checkpoint_id, session_index, meta_content.as_deref());
132→
133→    for path in &candidates {
134→        if let Ok(content) = read_blob(&repo, path) {
135→            return Ok(session::read_transcript(&content));
136→        }
137→    }
138→
139→    Err(format!("Transcript not found for checkpoint {} session {}", checkpoint_id, session_index))
140→}
