728→#[tauri::command]
729→fn watch_repo(
730→    repo_path: String,
731→    app: tauri::AppHandle,
732→    state: State<'_, Mutex<AppState>>,
733→) -> Result<(), String> {
734→    let mut app_state = state.lock().map_err(|_| "State lock error".to_string())?;
735→
736→    // Don't double-watch
737→    if app_state.watched_repos.contains(&repo_path) {
738→        return Ok(());
739→    }
740→    app_state.watched_repos.insert(repo_path.clone());
741→
742→    let app_handle = app.clone();
743→    let repo_path_for_closure = repo_path.clone();
744→    watcher::watch_repo(&repo_path, move |event| {
745→        let event_name = match event {
746→            watcher::WatchEvent::CheckpointChanged => "checkpoint-changed",
747→            watcher::WatchEvent::SessionChanged(_) => "session-changed",
748→            watcher::WatchEvent::ConfigChanged => "config-changed",
749→        };
750→        let _ = app_handle.emit(event_name, serde_json::json!({
751→            "repoPath": repo_path_for_closure,
752→        }));
753→    })?;
754→
755→    Ok(())
