791→#[cfg_attr(mobile, tauri::mobile_entry_point)]
792→pub fn run() {
793→    tauri::Builder::default()
794→        .plugin(tauri_plugin_opener::init())
795→        .plugin(tauri_plugin_dialog::init())
796→        .plugin(tauri_plugin_window_state::Builder::default().build())
797→        .manage(Mutex::new(AppState {
798→            watched_repos: HashSet::new(),
799→        }))
800→        .manage(Mutex::new(ghostty::GhosttyState::new()))
801→        .setup(|app| {
802→            // Start the ghostty tick loop on the MAIN THREAD via a Cocoa timer.
803→            // ghostty_app_tick processes Cocoa/Metal events and must run on the
804→            // main thread.
805→            {
806→                use block2::RcBlock;
807→                use objc2_foundation::NSTimer;
808→
809→                let handle = app.handle().clone();
810→                let tick_block = RcBlock::new(move |_timer| {
811→                    let state = handle.state::<Mutex<ghostty::GhosttyState>>();
812→                    let mutex = state.inner();
813→                    if let Ok(gs) = mutex.lock() {
814→                        if let Some(app) = gs.app.as_ref() {
815→                            app.tick();
816→                        }
817→                    }
818→                });
819→
820→                let _tick_timer = unsafe {
821→                    NSTimer::scheduledTimerWithTimeInterval_repeats_block(
822→                        1.0 / 60.0,
823→                        true,
824→                        &tick_block,
825→                    )
826→                };
827→            }
828→
829→            // System tray
830→            use tauri::menu::{MenuBuilder, MenuItemBuilder};
831→            use tauri::tray::TrayIconBuilder;
832→            use tauri::Manager;
833→
834→            let show = MenuItemBuilder::with_id("show", "Show Entire").build(app)?;
835→            let quit = MenuItemBuilder::with_id("quit", "Quit").build(app)?;
836→            let menu = MenuBuilder::new(app)
837→                .item(&show)
838→                .separator()
839→                .item(&quit)
840→                .build()?;
841→
842→            let _tray = TrayIconBuilder::new()
843→                .tooltip("Entire Desktop")
844→                .menu(&menu)
845→                .on_menu_event(move |app, event| {
846→                    match event.id().as_ref() {
847→                        "show" => {
848→                            if let Some(window) = app.get_webview_window("main") {
849→                                let _ = window.show();
850→                                let _ = window.set_focus();
851→                            }
852→                        }
853→                        "quit" => {
854→                            app.exit(0);
855→                        }
856→                        _ => {}
857→                    }
858→                })
859→                .on_tray_icon_event(|tray, event| {
860→                    if let tauri::tray::TrayIconEvent::Click { .. } = event {
861→                        let app = tray.app_handle();
862→                        if let Some(window) = app.get_webview_window("main") {
863→                            let _ = window.show();
864→                            let _ = window.set_focus();
865→                        }
866→                    }
867→                })
868→                .build(app)?;
869→
870→            Ok(())
871→        })
872→        .invoke_handler(tauri::generate_handler![
873→            debug_log,
874→            list_repos,
875→            register_repo,
876→            unregister_repo,
877→            block_repo,
878→            get_app_settings,
879→            save_app_settings,
880→            create_worktree,
881→            delete_worktree,
882→            delete_branch,
883→            list_checkpoints,
884→            get_transcript,
885→            get_checkpoint_diff,
886→            run_checkpoint_semantic_review,
887→            get_branch_diff,
888→            list_sessions,
889→            get_entire_settings,
890→            get_entire_logs,
891→            get_checkpoint_logs,
892→            get_raw_checkpoint_metadata,
893→            get_raw_session_file,
894→            launch_ghostty_agent,
895→            list_trails,
896→            watch_repo,
897→            ghostty::commands::ghostty_create_surface,
898→            ghostty::commands::ghostty_destroy_surface,
899→            ghostty::commands::ghostty_update_overlay,
900→            ghostty::commands::ghostty_show_overlay,
901→            ghostty::commands::ghostty_focus_overlay,
902→            ghostty::commands::ghostty_send_text,
903→            list_journal_entries,
904→            get_journal_entry,
905→            generate_journal_entry,
906→            get_journal_dates,
907→        ])
908→        .run(tauri::generate_context!())
909→        .expect("error while running tauri application");
910→}
