265→/// Global Ghostty application instance. One per process.
266→pub struct GhosttyApp {
267→    inner: *mut c_void,
268→}
269→
270→// SAFETY: GhosttyApp is only accessed through Mutex<GhosttyState>
271→unsafe impl Send for GhosttyApp {}
272→unsafe impl Sync for GhosttyApp {}
273→
274→#[allow(dead_code)]
275→impl GhosttyApp {
276→    /// Initialize libghostty and create the app with the user's default config.
277→    pub fn new() -> Result<Self, String> {
278→        unsafe {
279→            // Initialize the library
280→            let ret = ghostty_init(0, ptr::null_mut());
281→            if ret != 0 {
282→                return Err(format!("ghostty_init failed with code {}", ret));
283→            }
284→
285→            // Create and load config (reads ~/.config/ghostty/config automatically)
286→            let config = ghostty_config_new();
287→            if config.is_null() {
288→                return Err("ghostty_config_new returned null".into());
289→            }
290→            ghostty_config_load_default_files(config);
291→            ghostty_config_finalize(config);
292→
293→            // Set up runtime callbacks
294→            let runtime_config = GhosttyRuntimeConfig {
295→                userdata: ptr::null_mut(),
296→                supports_selection_clipboard: false,
297→                wakeup_cb: runtime_wakeup,
298→                action_cb: runtime_action,
299→                read_clipboard_cb: runtime_read_clipboard,
300→                confirm_read_clipboard_cb: runtime_confirm_read_clipboard,
301→                write_clipboard_cb: runtime_write_clipboard,
302→                close_surface_cb: runtime_close_surface,
303→            };
304→
305→            let app = ghostty_app_new(&runtime_config, config);
306→            if app.is_null() {
307→                ghostty_config_free(config);
308→                return Err("ghostty_app_new returned null".into());
309→            }
310→
311→            Ok(Self { inner: app })
312→        }
313→    }
314→
315→    /// Pump the ghostty event loop. Call from a timer or run loop.
316→    pub fn tick(&self) {
317→        unsafe { ghostty_app_tick(self.inner) }
318→    }
319→
320→    pub fn set_focus(&self, focused: bool) {
321→        unsafe { ghostty_app_set_focus(self.inner, focused) }
322→    }
323→
324→    pub fn raw(&self) -> *mut c_void {
325→        self.inner
326→    }
327→}
328→
329→impl Drop for GhosttyApp {
330→    fn drop(&mut self) {
331→        if !self.inner.is_null() {
332→            unsafe { ghostty_app_free(self.inner) };
333→        }
334→    }
335→}
