451→
452→    pub fn mouse_button(
453→        &self,
454→        state: GhosttyMouseState,
455→        button: GhosttyMouseButton,
456→        mods: GhosttyInputMods,
457→    ) -> bool {
458→        unsafe { ghostty_surface_mouse_button(self.inner, state, button, mods) }
459→    }
460→
461→    pub fn mouse_pos(&self, x: f64, y: f64, mods: GhosttyInputMods) {
462→        unsafe { ghostty_surface_mouse_pos(self.inner, x, y, mods) };
