 39→// --- Registry persistence for manually registered repos ---
 40→
 41→#[derive(Debug, Serialize, Deserialize, Default)]
 42→struct RepoRegistry {
 43→    repos: Vec<String>,
 44→    #[serde(default)]
 45→    blocked: Vec<String>,
 46→}
 47→
 48→fn registry_path() -> PathBuf {
 49→    let home = dirs_next().unwrap_or_default();
 50→    PathBuf::from(home).join(".entire").join("registered-repos.json")
 51→}
 52→
 53→fn load_registry() -> RepoRegistry {
 54→    let path = registry_path();
 55→    let content = match fs::read_to_string(&path) {
 56→        Ok(c) => c,
 57→        Err(_) => return RepoRegistry::default(),
 58→    };
 59→    serde_json::from_str::<RepoRegistry>(&content).unwrap_or_default()
 60→}
 61→
 62→fn load_registered_repos() -> Vec<String> {
 63→    load_registry().repos
 64→}
 65→
 66→fn save_registry(registry: &RepoRegistry) -> Result<(), String> {
 67→    let path = registry_path();
 68→    if let Some(parent) = path.parent() {
 69→        fs::create_dir_all(parent).map_err(|e| format!("Failed to create ~/.entire: {}", e))?;
 70→    }
 71→    let content =
 72→        serde_json::to_string_pretty(registry).map_err(|e| format!("Failed to serialize: {}", e))?;
 73→    fs::write(&path, content).map_err(|e| format!("Failed to write registry: {}", e))
 74→}
 75→
 76→fn save_registered_repos(repos: &[String]) -> Result<(), String> {
 77→    let mut registry = load_registry();
 78→    registry.repos = repos.to_vec();
 79→    save_registry(&registry)
 80→}
