417→    }
418→
419→    setTabs(cleanup.remainingTabs);
420→
421→    if (cleanup.nextActiveTabId && cleanup.nextActiveTabId !== activeTabId) {
422→      setActiveTabId(cleanup.nextActiveTabId);
423→    }
424→
425→    setWorkspaceMap((prev) => {
